@pytest.mark.asyncio
async def test_anthropic_chat() -> None:
    """Basic chat completion via the Anthropic provider (claude-3-5-sonnet-20241022) with system and user messages."""
    request = ChatCompletionRequest.from_json(
        '{"max_tokens":16,"messages":[{"content":"You are a helpful assistant.","role":"system"},{"content":"Say hello in one word.","role":"user"}],"model":"anthropic/claude-3-5-sonnet-20241022","temperature":0}'
    )
    client = create_client(
        api_key="test-key",
        base_url=os.environ["MOCK_SERVER_URL"] + "/fixtures/anthropic_chat",
    )
    result = await client.chat(request)
    assert len(result.choices) == 1  # noqa: S101
    assert _alef_e2e_text(result.choices[0].message.content).lower() == "Hello!".lower()  # noqa: S101
    assert _alef_e2e_text(result.choices[0].finish_reason).lower() == "stop".lower()  # noqa: S101
    assert result.model.strip() == "claude-3-5-sonnet-20241022"  # noqa: S101
    assert result.usage.total_tokens == 23  # noqa: S101


